/* Synthesizable Finite State Machine Traffic Controller */
module traffic_controller(
    input clk,
    input rst,
    output reg red,
    output reg yellow,
    output reg green
);

  typedef enum reg [1:0] {
    GREEN_STATE  = 2'b00,
    YELLOW_STATE = 2'b01,
    RED_STATE    = 2'b10
  } state_type;

  state_type state, next_state;
  reg [27:0] counter;

  always @(posedge clk or posedge rst) begin
    if (rst) begin
      state <= GREEN_STATE;
      counter <= 0;
    end else begin
      if (counter == 28'd250_000_000) begin // 5 seconds at 50MHz
        state <= next_state;
        counter <= 0;
      end else begin
        counter <= counter + 1;
      end
    end
  end

  // FSM Next State Logic
  always @(*) begin
    case (state)
      GREEN_STATE:  next_state = YELLOW_STATE;
      YELLOW_STATE: next_state = RED_STATE;
      RED_STATE:    next_state = GREEN_STATE;
      default:      next_state = GREEN_STATE;
    endcase
  end
endmodule

