module vga_controller(
    input pixel_clk, // 25.175 MHz for 640x480
    output reg hsync,
    output reg vsync,
    output [3:0] r, g, b
);

  reg [9:0] h_count = 0;
  reg [9:0] v_count = 0;

  always @(posedge pixel_clk) begin
    if (h_count == 799) begin
      h_count <= 0;
      if (v_count == 524) v_count <= 0;
      else v_count <= v_count + 1;
    end else begin
      h_count <= h_count + 1;
    end

