/* Synthesizable 4-Bit Calculator (Add, Sub, Mul, Div) */
module calculator(
    input [3:0] a,
    input [3:0] b,
    input [1:0] op,
    output reg [7:0] result
);

  always @(*) begin
    case (op)
      2'b00: result = a + b;
      2'b01: result = a - b;
      2'b10: result = a * b;
      2'b11: result = (b != 0) ? (a / b) : 8'hEE; // Error if div by 0
      default: result = 8'h00;
    endcase
  end
endmodule
